from anthropic import Anthropic

client = Anthropic()

# Tools define பண்றோம்
tools = [
    {
        "name": "web_search",
        "description": "Search the web for current information",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search query"}
            },
            "required": ["query"]
        }
    }
]

# Agent loop
messages = [{"role": "user", "content": "What is the latest news about AI?"}]

while True:
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        tools=tools,
        messages=messages
    )

    if response.stop_reason == "end_turn":
        print(response.content[0].text)  # Final answer
        break
    elif response.stop_reason == "tool_use":
        tool_result = execute_tool(response)  # Tool execute பண்றோம்
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_result})

from sklearn.metrics import confusion_matrix
import pandas as pd

def check_fairness(model, X_test, y_test, sensitive_attr):
    predictions = model.predict(X_test)
    results = []

    for group in X_test[sensitive_attr].unique():
        mask = X_test[sensitive_attr] == group
        group_pred = predictions[mask]
        group_true = y_test[mask]

        tp = ((group_pred == 1) & (group_true == 1)).sum()
        fp = ((group_pred == 1) & (group_true == 0)).sum()
        fn = ((group_pred == 0) & (group_true == 1)).sum()
        tn = ((group_pred == 0) & (group_true == 0)).sum()

        results.append({
            "group": group,
            "true_positive_rate": tp / (tp + fn) if (tp + fn) > 0 else 0,
            "false_positive_rate": fp / (fp + tn) if (fp + tn) > 0 else 0,
            "precision": tp / (tp + fp) if (tp + fp) > 0 else 0
        })

    return pd.DataFrame(results)
